const PROCESSING_FEE = 5;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

const COMPONENT_TYPES = new Set(["rune"]);
const COMPONENT_BLOCK_PREMIUM = 60;
const COMPONENT_BLOCK_SIZE = 3;

export const quote = (customer: unknown, items: unknown[]): number => {
  const typedItems = items as { type: string }[];
  const counts: Record<string, number> = {};
  for (const item of typedItems) {
    counts[item.type] = (counts[item.type] ?? 0) + 1;
  }
  let totalBase = 0;
  for (const [type, count] of Object.entries(counts)) {
    if (count === COMPONENT_BLOCK_SIZE && COMPONENT_TYPES.has(type)) {
      totalBase += COMPONENT_BLOCK_PREMIUM;
    } else {
      totalBase += count * BASE_PREMIUM[type];
    }
  }
  return totalBase + PROCESSING_FEE;
};

export const claim = (policy: unknown, incident: unknown): unknown => {
  return undefined as unknown;
};

