import { describe, it, expect } from "vitest";
import { quote, claim } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("quote", () => {
    it("should return 5 G processing fee for empty item list", () => {
      const customer = { yearsWithMHPCO: 0, contractCount: 0 };
      expect(quote(customer, [])).toBe(5);
    });
    it("should return base premium plus processing fee for a single sword", () => {
      const customer = { yearsWithMHPCO: 0, contractCount: 0 };
      const items = [{ type: "sword", material: "steel", enchantment: 0, cursed: false }];
      expect(quote(customer, items)).toBe(105);
    });
    it("should return base premium plus processing fee for a single amulet", () => {
      const customer = { yearsWithMHPCO: 0, contractCount: 0 };
      const items = [{ type: "amulet", material: "silver", enchantment: 0, cursed: false }];
      expect(quote(customer, items)).toBe(65);
    });
    it("should return base premium plus processing fee for a single staff", () => {
      const customer = { yearsWithMHPCO: 0, contractCount: 0 };
      const items = [{ type: "staff", material: "oak", enchantment: 0, cursed: false }];
      expect(quote(customer, items)).toBe(85);
    });
    it("should return base premium plus processing fee for a single potion", () => {
      const customer = { yearsWithMHPCO: 0, contractCount: 0 };
      const items = [{ type: "potion", material: "liquid", enchantment: 0, cursed: false }];
      expect(quote(customer, items)).toBe(45);
    });
    it("should return base premium plus processing fee for a single component (rune)", () => {
      const customer = { yearsWithMHPCO: 0, contractCount: 0 };
      const items = [{ type: "rune" }];
      expect(quote(customer, items)).toBe(30);
    });
    it("should sum base premiums for multiple items", () => {
      const customer = { yearsWithMHPCO: 0, contractCount: 0 };
      const items = [
        { type: "sword", material: "steel", enchantment: 0, cursed: false },
        { type: "amulet", material: "silver", enchantment: 0, cursed: false },
      ];
      expect(quote(customer, items)).toBe(165);
    });
    it("should apply block pricing for exactly 3 alike components", () => {
      const customer = { yearsWithMHPCO: 0, contractCount: 0 };
      const items = [{ type: "rune" }, { type: "rune" }, { type: "rune" }];
      expect(quote(customer, items)).toBe(65);
    });
    it("should NOT apply block pricing for 2 alike components", () => {
      const customer = { yearsWithMHPCO: 0, contractCount: 0 };
      const items = [{ type: "rune" }, { type: "rune" }];
      expect(quote(customer, items)).toBe(55);
    });
    it("should NOT apply block pricing for 4 alike components", () => {
      const customer = { yearsWithMHPCO: 0, contractCount: 0 };
      const items = [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }];
      expect(quote(customer, items)).toBe(105);
    });
    it("should NOT apply block pricing for mixed component types", () => {
      const customer = { yearsWithMHPCO: 0, contractCount: 0 };
      const items = [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }];
      expect(quote(customer, items)).toBe(80);
    });
    it("should apply cursed item surcharge (50%) to the cursed item's base premium only", () => {
      const customer = { yearsWithMHPCO: 0, contractCount: 0 };
      const items = [
        { type: "sword", material: "steel", enchantment: 0, cursed: true },
        { type: "amulet", material: "silver", enchantment: 0, cursed: false },
      ];
      // cursed sword: base 100 + 50% surcharge 50 = 150
      // plain amulet: base 60
      // total base: 210, + 5 fee = 215
      expect(quote(customer, items)).toBe(215);
    });
    it("should apply high enchantment surcharge (30%) for enchantment level >= 5", () => {
      const customer = { yearsWithMHPCO: 0, contractCount: 0 };
      const items = [{ type: "sword", material: "steel", enchantment: 5, cursed: false }];
      // sword base 100 + 30% surcharge 30 = 130 + 5 fee = 135
      expect(quote(customer, items)).toBe(135);
    });
    it.todo("should NOT apply high enchantment surcharge for enchantment level < 5");
    it.todo("should apply both cursed and high enchantment surcharges when applicable");
    it.todo("should apply loyalty discount (20%) for customers with >= 2 years");
    it.todo("should NOT apply loyalty discount for customers with < 2 years");
    it.todo("should apply first insurance surcharge (10%) to all items in a quote");
    it.todo("should apply follow-up contract discount (15%) for subsequent quotes");
    it.todo("should round final premium up in MHPCO's favor");
    it.todo("should exit with non-zero status for unknown item type");
  });

  describe("claim", () => {
    it.todo("should pay damage minus 100 G deductible for standard item");
    it.todo("should apply 100 G deductible per damage event for multiple items");
    it.todo("should reimburse at 50% for items with enchantment level >= 8");
    it.todo("should fully reimburse damage to dragon material items");
    it.todo("should apply 50% rule (not full) when both enchantment >= 8 and dragon material");
    it.todo("should cap total payout at twice the insurance sum across claims");
