      const items = [{ type: "sword", material: "steel", enchantment: 5, cursed: true }];
      // policyBase: 100; cursed: 50; enchantment: 30; first insurance: 10
      // total: 100 + 50 + 30 + 10 = 190 + 5 fee = 195
      expect(quote(customer, items)).toBe(195);
    });
